async def platform_orchestrator_node(state: AgentState) -> dict:
    tasks = []
    for draft in state["creative_drafts"]:
        for platform in draft.get("target_platforms", []):
            agent = PLATFORM_AGENTS.get(platform)
            if agent:
                tasks.append(agent(draft, state))

    if not tasks:
        logger.warning("No platform tasks generated")
        return {"platform_posts": []}

    results = await asyncio.gather(*tasks, return_exceptions=True)

    posts, errors = [], []
    for i, result in enumerate(results):
        if isinstance(result, Exception):
            logger.error(f"Platform agent {i} failed: {result}")
            errors.append(str(result))
        else:
            posts.extend(result)

    if errors:
        logger.warning(f"{len(errors)} platform agent(s) failed (non-fatal)")
    return {"platform_posts": posts}
